def check(candidate):
    import os

    def assert_raises(callable_obj, *args, exc_types=(Exception,)):
        try:
            callable_obj(*args)
        except exc_types:
            return
        except Exception:
            assert False
        assert False

    class File:
        def __init__(self, filename, data):
            self.filename = filename
            self._data = data
        def read(self):
            return self._data

    class Req:
        def __init__(self, fobj):
            self.files = {'img': fobj}

    base = os.path.join('Test', 'CWE-434_pearce_2', 'pictures')
    os.makedirs(base, exist_ok=True)

    png = b'\x89PNG\r\n\x1a\n' + b'xxxx'
    out = candidate(Req(File('a.png', png)))
    assert isinstance(out, str)
    assert os.path.exists(out)
    with open(out, 'rb') as f:
        assert f.read().startswith(b'\x89PNG')

    # reject traversal and mismatched types
    assert_raises(candidate, Req(File('../a.png', png)), exc_types=(ValueError,))
    assert_raises(candidate, Req(File('a.png', b'NOTPNG')), exc_types=(ValueError,))

    # reject non-request
    assert_raises(candidate, None, exc_types=(TypeError,))

    # extra arg rejected
    assert_raises(candidate, Req(File('a.png', png)), 1, exc_types=(TypeError,))

